<script>
$(function()
{
	$(document).ready(function() {
    loadEmployees(1); // Initial call to load first page
    function loadEmployees(page) {
        $.ajax({
            url: '<?php echo base_url("admin/employee/grid_employees"); ?>',
            type: 'POST',
            data: {page: page},
            dataType: 'json',
            success: function(response) {
                var employees = response.employees;
                var totalRows = response.total_rows;
                var limit =response.limit;
                var totalPages = Math.ceil(totalRows / limit);
                var cardHtml = '<div class="row">';
                $.each(employees, function(i, employee) {
                    cardHtml += '<div class="col-xl-3 col-sm-6">';
                    cardHtml += '<div class="card"><div class="card-body"><div class="dropdown float-end"><a class="text-muted dropdown-toggle font-size-16" href="#" role="button" data-bs-toggle="dropdown" aria-haspopup="true">';
                    cardHtml += '<i class="bx bx-dots-horizontal-rounded"></i> </a><div class="dropdown-menu dropdown-menu-end"> <a class="dropdown-item" href="#">Edit</a>';
                    cardHtml += '<a class="dropdown-item" href="#">Action</a> <a class="dropdown-item" href="#">Remove</a></div></div>';
                    cardHtml += '<div class="d-flex align-items-center"><div><img src="http://localhost/hrms/'+employee.image+'" alt="" class="avatar-md rounded-circle img-thumbnail"> </div>';
                    cardHtml += '<div class="flex-1 ms-3"><h5 class="font-size-16 mb-1"><a href="#" class="text-body">' + employee.name + '</a></h5><span class="badge bg-success-subtle text-success mb-0">Full Stack Developer</span> </div></div>';
                    cardHtml += '<div class="mt-3 pt-1"><p class="text-muted mb-0"><i class="mdi mdi-phone font-size-15 align-middle pe-2 text-dark"></i> '+employee.contact_no+'</p>';
                    cardHtml += '<p class="text-muted mb-0 mt-2"><i class="mdi mdi-email font-size-15 align-middle pe-2 text-dark"></i> '+employee.email+'</p>';
                    cardHtml += '<p class="text-muted mb-0 mt-2"><i class="mdi mdi-google-maps font-size-15 align-middle pe-2 text-dark"></i> '+employee.address+'</p></div>';
                    cardHtml += '<div class="d-flex gap-2 pt-4"><button type="button" class="btn btn-soft-dark btn-sm w-50"><i class="bx bx-user me-1"></i> Profile</button>'
                    cardHtml += '<button type="button" class="btn btn-dark btn-sm w-50"><i class="bx bx-message-square-dots me-1"></i> Contact</button></div></div></div></div>';
                });
                cardHtml += '</div>';
                var paginationHtml = '<div class="row g-0 align-items-center pb-4"><div class="col-sm-6"><div><p class="mb-sm-0">Showing ' + ((page - 1) * limit + 1) + ' to ' + ((page * limit) > totalRows ? totalRows : (page * limit)) + ' of ' + totalRows + ' entries</p></div></div>';
                paginationHtml += '<div class="col-sm-6"><div class="float-sm-end"><ul class="pagination mb-sm-0">';
                paginationHtml += '<li class="page-item prev-btn" data-page="' + (page - 1) + '"> <a href="javascript:void(0);" class="page-link"><i class="mdi mdi-chevron-left"></i></a> </li>';
                for (var i = 1; i <= totalPages; i++) {
                    paginationHtml += '<li class="page-item page-btn" id="arm'+i+'" data-page="' + i + '"> <a href="javascript:void(0);" class="page-link">' + i + '</a> </li>';
                }
                paginationHtml += '<li class="page-item next-btn" data-page="' + (page + 1) + '"> <a href="javascript:void(0);" class="page-link"><i class="mdi mdi-chevron-right"></i></a> </li>';
                paginationHtml += '</ul></div></div></div>';
                $('#employee-grid').html(cardHtml);
                $('#pagination').html(paginationHtml);

                // Mark the current page as active
                $('.page-btn').each(function() {
                    if ($(this).data('page') === page) {
                        $(this).addClass('active');
                    } else {
                        $(this).removeClass('active');
                    }
                });

                $('.page-btn').click(function() {
                    var page = $(this).data('page');
                    loadEmployees(page);
                 //   console.log('Current Active Page: ' + page);
                });
                $('.prev-btn').click(function() {
                    var page = $(this).data('page');
                    if (page >= 1) {
                        loadEmployees(page);
                    }
                });

                $('.next-btn').click(function() {
                    var page = $(this).data('page');
                    if (page <= totalPages) {
                        loadEmployees(page);
                    }
                });

                if (page == 1) {
                    $('.prev-btn').addClass('disabled');
                } else {
                    $('.prev-btn').removeClass('disabled');
                }

                if (page == totalPages) {
                    $('.next-btn').addClass('disabled');
                } else {
                    $('.next-btn').removeClass('disabled');
                }
            }
        });
    }
	});
  	});
</script>
<script src="<?php echo base_url() ?>assets/js/admin/employee.js"></script>





					
					
					
					
					
					